VERIFICATION: Scan your response before sending. Remove ALL markdown characters including #, *, -, and **.
    `;

    const history = messages
        .filter(m => m.content?.trim())
        .map(m => ({
            role: m.role === 'assistant' ? 'model' : 'user',
